import { defineConfig } from "vitest/config"
import path from "path"

export default defineConfig({
  test: {
    environment: "node",
    globals: true,
  },
  resolve: {
    alias: {
      "@": path.resolve(__dirname, "."),
    },
  },
})

import { describe, it, expect } from "vitest"
import {
  clean,
  findSection,
  extractSubtitulo,
  extractDescricao,
  extractDestaques,
  extractFuncionalidades,
  extractIntegracoes,
  extractPrazoTotal,
  extractCronogramaFases,
  extractValorTotal,
  extractParcelas,
  extractEntregaveis,
} from "./proposal-pdf-utils"
import type { ProposalSection } from "./proposal-types"

// ── clean ──────────────────────────────────────────────────────────────────

describe("clean", () => {
  it("deve remover marcadores **bold**", () => {
    expect(clean("**Texto em negrito**")).toBe("Texto em negrito")
  })
  it("deve remover marcadores *italic*", () => {
    expect(clean("*Texto itálico*")).toBe("Texto itálico")
  })
  it("deve fazer trim de espaços", () => {
    expect(clean("  texto  ")).toBe("texto")
  })
  it("deve retornar string vazia quando vazio", () => {
    expect(clean("")).toBe("")
  })
})

// ── findSection ────────────────────────────────────────────────────────────

describe("findSection", () => {
  const sections: ProposalSection[] = [
    { key: "sobre-o-projeto", title: "Sobre o Projeto", content: "conteudo A" },
    { key: "escopo",          title: "Escopo dos Serviços", content: "conteudo B" },
    { key: "cronograma",      title: "Cronograma", content: "conteudo C" },
    { key: "investimento",    title: "Investimento", content: "conteudo D" },
  ]

  it("deve encontrar seção por keyword no key", () => {
    expect(findSection(sections, "escopo")?.content).toBe("conteudo B")
  })
  it("deve encontrar seção por keyword no title", () => {
    expect(findSection(sections, "cronograma")?.content).toBe("conteudo C")
  })
  it("deve retornar undefined quando não encontra", () => {
    expect(findSection(sections, "inexistente")).toBeUndefined()
  })
  it("deve usar o primeiro match quando múltiplas keywords batem", () => {
    expect(findSection(sections, "investimento", "escopo")?.key).toBe("escopo")
  })
})

// ── extractSubtitulo ───────────────────────────────────────────────────────

describe("extractSubtitulo", () => {
  it("deve priorizar o campo projeto quando preenchido", () => {
    expect(extractSubtitulo("### Outro título\nconteudo", "Meu Projeto")).toBe("Meu Projeto")
  })
  it("deve usar heading ### quando projeto está vazio", () => {
    expect(extractSubtitulo("### Quiz Interativo — Easy Salon\nconteudo", "")).toBe("Quiz Interativo — Easy Salon")
  })
  it("deve usar primeiro bold quando não há h3", () => {
    expect(extractSubtitulo("**Título do Projeto**\nalgo", "")).toBe("Título do Projeto")
  })
  it("deve retornar primeira linha quando não há h3 nem bold", () => {
    expect(extractSubtitulo("Linha simples\n- bullet", "")).toBe("Linha simples")
  })
})

// ── extractDescricao ───────────────────────────────────────────────────────

describe("extractDescricao", () => {
  it("deve retornar o primeiro parágrafo simples ignorando headings e bullets", () => {
    const content = "## Heading\n- bullet\nEste é o parágrafo real.\n- outro bullet"
    expect(extractDescricao(content)).toBe("Este é o parágrafo real.")
  })
  it("deve ignorar linhas que começam com *", () => {
    const content = "**bold line**\nParágrafo limpo."
    expect(extractDescricao(content)).toBe("Parágrafo limpo.")
  })
  it("deve ignorar listas numeradas", () => {
    const content = "1. item da lista\nTexto descritivo aqui."
    expect(extractDescricao(content)).toBe("Texto descritivo aqui.")
  })
  it("deve retornar string vazia quando só há bullets e headings", () => {
    const content = "## Título\n- item1\n- item2"
    expect(extractDescricao(content)).toBe("")
  })
})

// ── extractDestaques ───────────────────────────────────────────────────────

describe("extractDestaques", () => {
  it("deve extrair duas linhas bold isoladas como destaques", () => {
    const content = "Parágrafo normal.\n**Destaque principal da solução.**\n**Entrega ao cliente.**\nOutra linha."
    const [d1, d2] = extractDestaques(content)
    expect(d1).toBe("Destaque principal da solução.")
    expect(d2).toBe("Entrega ao cliente.")
  })
  it("deve retornar strings vazias quando não há bold isolado", () => {
    const content = "Linha normal.\nOutra linha."
    const [d1, d2] = extractDestaques(content)
    expect(d1).toBe("")
    expect(d2).toBe("")
  })
})

// ── extractFuncionalidades ─────────────────────────────────────────────────

describe("extractFuncionalidades", () => {
  it("deve converter padrão '1. **Nome** — Desc' para HTML correto", () => {
    const content = "1. **Formulário de Captura** — Tela inicial com campos de Nome e Email."
    const result = extractFuncionalidades(content)
    expect(result).toContain('<span class="n">1.</span>')
    expect(result).toContain("<strong>Formulário de Captura</strong>")
    expect(result).toContain("Tela inicial com campos de Nome e Email.")
  })
  it("deve converter padrão '1. Nome — Desc' para HTML", () => {
    const content = "1. Quiz Interativo — Interface para TV touch."
    const result = extractFuncionalidades(content)
    expect(result).toContain('<span class="n">1.</span>')
    expect(result).toContain("<strong>Quiz Interativo</strong>")
  })
  it("deve converter padrão '- **Nome**: Desc' para HTML numerado", () => {
    const content = "- **Exportação de Dados**: Gera arquivo Excel ao final."
    const result = extractFuncionalidades(content)
    expect(result).toContain('<span class="n">1.</span>')
    expect(result).toContain("<strong>Exportação de Dados</strong>")
  })
  it("deve usar fallback de bullets simples quando nenhum padrão bate", () => {
    const content = "- Feature A\n- Feature B\n- Feature C"
    const result = extractFuncionalidades(content)
    expect(result).toContain("Feature A")
    expect(result).toContain('<span class="n">1.</span>')
  })
})

// ── extractPrazoTotal ──────────────────────────────────────────────────────

describe("extractPrazoTotal", () => {
  it("deve extrair prazo após palavra-chave 'Prazo total'", () => {
    expect(extractPrazoTotal("Prazo total estimado: 4,5 semanas")).toBe("4,5 semanas")
  })
  it("deve extrair duração simples no texto", () => {
    expect(extractPrazoTotal("O projeto dura 3 meses no total.")).toBe("3 meses")
  })
  it("deve retornar 'A definir' quando não encontra duração", () => {
    expect(extractPrazoTotal("Sem informação de prazo aqui.")).toBe("A definir")
  })
})

// ── extractCronogramaFases ─────────────────────────────────────────────────

describe("extractCronogramaFases", () => {
  it("deve converter padrão 'Fase N - Desc | Período' para HTML", () => {
    const content = "Fase 1 - Planejamento | Semanas 1-2\nFase 2 - Desenvolvimento | Semanas 3-8"
    const result = extractCronogramaFases(content)
    expect(result).toContain('<span class="lbl">Fase 1:</span>')
    expect(result).toContain("Planejamento")
    expect(result).toContain('<span class="lbl">Fase 2:</span>')
  })
  it("deve converter padrão 'Fase N - Desc' sem período para HTML", () => {
    const content = "Fase 3 - Homologação e Go-Live"
    const result = extractCronogramaFases(content)
    expect(result).toContain('<span class="lbl">Fase 3:</span>')
    expect(result).toContain("Homologação e Go-Live")
  })
  it("deve retornar fallback quando conteúdo está vazio", () => {
    expect(extractCronogramaFases("")).toContain("A definir")
  })
})

// ── extractValorTotal ──────────────────────────────────────────────────────

describe("extractValorTotal", () => {
  it("deve extrair valor da linha que contém 'Total' e 'R$'", () => {
    const content = "Frontend | 1 | R$ 15.000\nBackend | 1 | R$ 20.000\nTotal | | R$ 35.000"
    expect(extractValorTotal(content)).toBe("R$ 35.000")
  })
  it("deve extrair primeiro R$ quando não há linha de total", () => {
    expect(extractValorTotal("Investimento de R$ 50.000")).toBe("R$ 50.000")
  })
  it("deve retornar 'A definir' quando não há valor", () => {
    expect(extractValorTotal("Sem valor definido")).toBe("A definir")
  })
})

// ── extractParcelas ────────────────────────────────────────────────────────

describe("extractParcelas", () => {
  it("deve extrair 3 parcelas nomeadas com R$", () => {
    const content = [
      "1ª parcela: R$ 6.667 na assinatura",
      "2ª parcela: R$ 6.667",
      "3ª parcela: R$ 6.666",
    ].join("\n")
    const p = extractParcelas(content)
    expect(p.v1).toBe("R$ 6.667")
    expect(p.v2).toBe("R$ 6.667")
    expect(p.v3).toBe("R$ 6.666")
  })
  it("deve usar fallback de valores em ordem quando não há labels de parcela", () => {
    const content = "Pagamento: R$ 10.000 na entrada e R$ 10.000 no final"
    const p = extractParcelas(content)
    expect(p.v1).toBe("R$ 10.000")
    expect(p.v2).toBe("R$ 10.000")
  })
  it("deve usar 'Pós-homologação' como cond3 quando menciona homologação", () => {
    const content = "3ª parcela pós-homologação: R$ 6.666"
    const p = extractParcelas(content)
    expect(p.cond3.toLowerCase()).toContain("pós")
  })
  it("deve retornar 'A definir' para parcelas ausentes", () => {
    const p = extractParcelas("")
    expect(p.v1).toBe("A definir")
    expect(p.v2).toBe("A definir")
    expect(p.v3).toBe("A definir")
  })
})

// ── extractEntregaveis ─────────────────────────────────────────────────────

describe("extractEntregaveis", () => {
  it("deve extrair bullets com keywords de entregável", () => {
    const content = "- Protótipos no Figma\n- Código fonte no repositório Git\n- Sistema em produção"
    const result = extractEntregaveis(content)
    expect(result).toContain("<li>Protótipos no Figma</li>")
    expect(result).toContain("<li>Código fonte no repositório Git</li>")
  })
  it("deve retornar lista padrão quando nenhum bullet tem keyword de entregável", () => {
    const result = extractEntregaveis("Texto sem keywords de entregável.")
    expect(result).toContain("Protótipos de Alta Fidelidade (Figma)")
    expect(result).toContain("Sistema em Produção")
  })
})

import type { ProposalSection, ProposalModelo } from "@/lib/proposal-types"
import { formatDateShort } from "@/lib/proposal-types"

export function clean(text: string): string {
  return text.replace(/\*\*/g, "").replace(/\*/g, "").trim()
}

export function findSection(sections: ProposalSection[], ...keywords: string[]): ProposalSection | undefined {
  return sections.find((s) =>
    keywords.some((k) => s.key.toLowerCase().includes(k) || s.title.toLowerCase().includes(k))
  )
}

export function extractSubtitulo(content: string, projeto: string): string {
  if (projeto) return projeto
  const h3 = content.match(/^###\s+(.+)$/m)
  if (h3) return clean(h3[1])
  const bold = content.match(/\*\*(.+?)\*\*/)
  if (bold) return bold[1]
  return clean(content.split("\n").find((l) => l.trim()) ?? "Projeto")
}

export function extractDescricao(content: string): string {
  const lines = content.split("\n")
  const para = lines.find((l) => {
    const t = l.trim()
    return t && !t.startsWith("#") && !t.startsWith("-") && !t.startsWith("*") && !/^\d+\./.test(t)
  })
  return clean(para ?? "")
}

export function extractDestaques(content: string): [string, string] {
  const boldLines = content
    .split("\n")
    .filter((l) => l.trim().startsWith("**") && l.trim().endsWith("**"))
    .map((l) => clean(l))
  return [boldLines[0] ?? "", boldLines[1] ?? ""]
}

