    expect(tokens.NOME_CLIENTE).toBe("Easy Salon")
    expect(tokens.CLIENTE_EMPRESA).toBe("João Silva")
    expect(tokens.TIPO_ESCOPO).toBe("Escopo Fechado")
    expect(tokens.NOME_EMPRESA).toBe("Wa Project")
    expect(tokens.TITULO_PROPOSTA).toBe("Proposta Comercial")
    expect(tokens.DIAS_VALIDADE).toBe("30")
  })

  it("deve mapear projeto e funcionalidades com HTML estruturado", () => {
