    expect(tokens.SUBTITULO_PROJETO).toBe("Sistema de Gestão para Salão")
    expect(tokens.DESCRICAO_PROJETO).toContain("<p>Um sistema completo para salões de beleza.</p>")
    expect(tokens.LISTA_FUNCIONALIDADES).toContain('<div class="func-item">')
    expect(tokens.LISTA_FUNCIONALIDADES).toContain("Agendamento Online")
