    const tokens = buildProposalTokens(emptyParams)

    expect(tokens.CLIENTE_EMPRESA).toBe("Empresa Teste") // fallback para empresa
    expect(tokens.TIPO_ESCOPO).toBe("Escopo Fechado") // fallback default
    expect(tokens.VALOR_TOTAL).toContain("A definir")
    expect(tokens.LISTA_ENTREGAVEIS).toContain("Protótipos de Alta Fidelidade") // lista padrão
  })

  it("deve incluir variáveis de conteúdo fixo", () => {
    const tokens = buildProposalTokens(params)

    expect(tokens.TITULO_SOBRE_EMPRESA).toBe("Sobre a Wa Project")
